a.large_category_idx) as large_category_name, program_classification1, program_classification2, program_classification3, program_subject, program_age_div, (SELECT code_name FROM TEACH_CODE2 WHERE teach_code = a.program_subject) as program_subject_name, (SELECT code_name FROM TEACH_CODE WHERE large_code = a.program_classification1 AND mid_code = '--' AND small_code = '--') as program_classification1_name, (SELECT code_name FROM TEACH_CODE WHERE large_code = a.program_classification1 AND mid_code = a.program_classification2 AND small_code = '--') as program_classification2_name, (SELECT code_name FROM TEACH_CODE WHERE large_code = a.program_classification1 AND mid_code = a.program_classification2 AND small_code = a.program_classification3) as program_classification3_name FROM TEACH a, TEACHER b, TEACH_CATEGORY c, TEACH_CATEGORY_GROUP d WHERE a.HOMEPAGE_ID = b.HOMEPAGE_ID(+) AND a.TEACHER_IDX = b.TEACHER_IDX(+) AND a.HOMEPAGE_ID = c.HOMEPAGE_ID(+) AND a.GROUP_IDX = c.GROUP_IDX(+) AND a.CATEGORY_IDX = c.CATEGORY_IDX(+) AND a.HOMEPAGE_ID = d.HOMEPAGE_ID(+) AND a.GROUP_IDX = d.GROUP_IDX(+) AND a.HOMEPAGE_ID = #{homepage_id}
