AND a.large_category_idx = #{large_category_idx}
AND a.GROUP_IDX = #{group_idx}
AND a.CATEGORY_IDX = #{category_idx}
AND TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDDHH24MI'), 'YYYY-MM-DD HH24:MI') >= TO_DATE(START_JOIN_DATE||' '||START_JOIN_TIME, 'YYYY-MM-DD HH24:MI') AND TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDDHH24MI'), 'YYYY-MM-DD HH24:MI') <= TO_DATE(END_JOIN_DATE||' '||END_JOIN_TIME, 'YYYY-MM-DD HH24:MI')
AND TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDDHH24MI'), 'YYYY-MM-DD HH24:MI') < TO_DATE(START_JOIN_DATE||' '||START_JOIN_TIME, 'YYYY-MM-DD HH24:MI')
AND TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDDHH24MI'), 'YYYY-MM-DD HH24:MI') > TO_DATE(END_JOIN_DATE||' '||END_JOIN_TIME, 'YYYY-MM-DD HH24:MI')
AND TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDDHH24MI'), 'YYYY-MM-DD HH24:MI') > TO_DATE(END_DATE||' '||END_TIME, 'YYYY-MM-DD HH24:MI')
AND TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDDHH24MI'), 'YYYY-MM-DD HH24:MI') >= TO_DATE(START_DATE||' '||START_TIME, 'YYYY-MM-DD HH24:MI') AND TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDDHH24MI'), 'YYYY-MM-DD HH24:MI') <= TO_DATE(END_DATE||' '||END_TIME, 'YYYY-MM-DD HH24:MI')
AND SUBSTR(a.START_DATE, 1, 4) = #{search_year}
