AND TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDDHH24MI'), 'YYYY-MM-DD HH24:MI') > TO_DATE(END_JOIN_DATE||' '||END_JOIN_TIME, 'YYYY-MM-DD HH24:MI')
