SELECT a.HOMEPAGE_ID, a.GROUP_IDX, a.CATEGORY_IDX, a.TEACH_IDX, a.TEACH_NAME, a.TEACH_DESC, a.TEACH_ETC, a.TEACH_STAGE, a.TEACH_TARGET, a.LIMIT_HAK, a.CALENDAR_VIEW_YN,a.LIMIT_HAK2, a.TEACH_LIMIT_COUNT, a.TEACH_JOIN_UNIT, a.TEACH_BACKUP_COUNT, a.TEACH_OFFLINE_COUNT, a.START_JOIN_DATE, a.START_JOIN_TIME, a.END_JOIN_DATE, a.END_JOIN_TIME, a.TEACH_DAY, a.START_DATE, a.START_TIME, a.PRINT_SEQ, a.TEACH_COUNT, a.END_DATE, a.END_TIME, a.PLAN_FILE_NAME, a.REAL_FILE_NAME, a.FILE_EXTENSION, a.FILE_SIZE, a.MEMBER_YN, a.USE_YN, a.USE_END_DATE, a.CERTIFICATE_YN, a.SURVEY_IDX, a.TEACHER_IDX, a.TEACH_SAME_LIMIT_COUNT, a.TEACH_JOIN_LIMIT_UNIT, a.TEACH_JOIN_LIMIT_VALUE, a.FAMILY_YN, a.TYPING_TEACHER_NAME, b.TEACHER_NAME, b.TEACHER_BIRTH, c.CATEGORY_NAME, d.GROUP_NAME, (SELECT COUNT(*) FROM STUDENT WHERE DELETE_YN = 'N' AND HOMEPAGE_ID = #{homepage_id} AND GROUP_IDX = #{group_idx} AND CATEGORY_IDX = #{category_idx} AND TEACH_IDX = #{teach_idx} AND APPLY_STATUS='1' AND APPLY_TYPE != 'CMS' GROUP BY TEACH_IDX) AS TEACH_JOIN_COUNT, (SELECT COUNT(*) FROM STUDENT WHERE DELETE_YN = 'N' AND HOMEPAGE_ID = #{homepage_id} AND GROUP_IDX = #{group_idx} AND CATEGORY_IDX = #{category_idx} AND TEACH_IDX = #{teach_idx} AND APPLY_STATUS='2' GROUP BY TEACH_IDX) AS TEACH_BACKUP_JOIN_COUNT, (SELECT COUNT(*) FROM STUDENT WHERE DELETE_YN = 'N' AND HOMEPAGE_ID = #{homepage_id} AND GROUP_IDX = #{group_idx} AND CATEGORY_IDX = #{category_idx} AND TEACH_IDX = #{teach_idx} AND APPLY_STATUS='1' AND APPLY_TYPE = 'CMS' GROUP BY TEACH_IDX) AS TEACH_OFF_JOIN_COUNT, CASE WHEN TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= a.end_date || ' ' || a.end_time THEN '1' ELSE '2' END teach_status, A.family_count_yn, A.agent_yn, A.school_info_yn, A.school_grade_yn, A.remark_yn, a.IMAGE_PLAN_FILE_NAME, a.IMAGE_REAL_FILE_NAME, a.IMAGE_FILE_EXTENSION, a.IMAGE_FILE_SIZE, a.LIMIT_HAK_YN, getCodeIdToCodeName('CMS', 'C0020', a.limit_hak) AS LIMIT_HAK_STR, getCodeIdToCodeName('CMS', 'C0020', a.limit_hak2) AS LIMIT_HAK2_STR, a.neis_location_yn, a.neis_cd_yn, a.neis_training_num_yn, a.large_category_idx, a.organization_yn, a.rank_yn, a.course_taken_yn, (SELECT code_name FROM TEACH_CODE2 WHERE teach_code = a.large_category_idx) as large_category_name, program_classification1, program_classification2, program_classification3, program_subject, program_age_div, (SELECT code_name FROM TEACH_CODE2 WHERE teach_code = a.program_subject) as program_subject_name, (SELECT code_name FROM TEACH_CODE WHERE large_code = a.program_classification1 AND mid_code = '--' AND small_code = '--') as program_classification1_name, (SELECT code_name FROM TEACH_CODE WHERE large_code = a.program_classification1 AND mid_code = a.program_classification2 AND small_code = '--') as program_classification2_name, (SELECT code_name FROM TEACH_CODE WHERE large_code = a.program_classification1 AND mid_code = a.program_classification2 AND small_code = a.program_classification3) as program_classification3_name, a.CANCLE_USE_YN, a.START_CANCLE_DATE, a.END_CANCLE_DATE, a.START_CANCLE_TIME, a.END_CANCLE_TIME, a.CANCLE_GUID, a.APPLY_LIMIT,a.adress_yn,a.black_yn, a.certificate_name FROM TEACH a, TEACHER b, TEACH_CATEGORY c, TEACH_CATEGORY_GROUP d WHERE a.HOMEPAGE_ID = b.HOMEPAGE_ID(+) AND a.TEACHER_IDX = b.TEACHER_IDX(+) AND a.HOMEPAGE_ID = c.HOMEPAGE_ID(+) AND a.GROUP_IDX = c.GROUP_IDX(+) AND a.CATEGORY_IDX = c.CATEGORY_IDX(+) AND a.HOMEPAGE_ID = d.HOMEPAGE_ID(+) AND a.GROUP_IDX = d.GROUP_IDX(+) AND a.HOMEPAGE_ID = #{homepage_id}
AND a.large_category_idx = #{large_category_idx}
AND a.GROUP_IDX = #{group_idx} AND a.CATEGORY_IDX = #{category_idx} AND a.TEACH_IDX = #{teach_idx} AND a.DELETE_YN = 'N'

