SELECT * FROM ( SELECT CASE WHEN TO_DATE(A.end_date || ' ' || A.end_time, 'YYYY-MM-DD HH24:MI') < SYSDATE THEN '9' WHEN A.status = 0 AND A.cancle_use_yn = 'Y' AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.start_cancle_date || ' ' || A.start_cancle_time AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.end_cancle_date || ' ' || A.end_cancle_time AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.start_date || ' ' || start_time AND A.apply_limit = 'Y' THEN '44' WHEN A.status = 0 AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.req_start_date AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.req_end_date AND A.teach_limit_count > A.teach_join_count THEN '0' WHEN A.status = 0 AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.req_start_date AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.req_end_date AND A.teach_limit_count <= A.teach_join_count AND A.teach_backup_count > A.teach_backup_join_count THEN '1' WHEN A.status = 0 AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.req_start_date AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.req_end_date AND A.teach_limit_count <= A.teach_join_count AND A.teach_backup_count <= A.teach_backup_join_count THEN '5' WHEN A.status = 0 AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.req_start_date THEN '6' WHEN A.status = 0 AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.req_end_date THEN '4' WHEN A.status = 1 AND A.apply_status = '1' AND (( A.cancle_use_yn != 'Y' AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.req_start_date AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.req_end_date ) OR ( A.cancle_use_yn = 'Y' AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.start_cancle_date || ' ' || A.start_cancle_time AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.end_cancle_date || ' ' || A.end_cancle_time AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.start_date || ' ' || start_time )) THEN '2' WHEN A.status = 1 AND A.apply_status = '1' AND A.cancle_use_yn = 'Y' AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.req_start_date AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.req_end_date THEN '10' WHEN A.status = 1 AND A.apply_status = '2' AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.req_start_date AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.req_end_date THEN '3' WHEN A.status = 1 AND A.apply_status = '99' AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.req_start_date AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.req_end_date THEN '7' WHEN A.status = 1 AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.req_end_date THEN '4' END as TEACH_STATUS,A.BLACK_YN, A.HOMEPAGE_ID, A.GROUP_IDX, A.CATEGORY_IDX, A.TEACH_IDX, A.TEACH_NAME, A.TEACH_DESC, A.TEACH_ETC, A.TEACH_STAGE, A.TEACH_TARGET, A.LIMIT_HAK, a.LIMIT_HAK2, A.TEACH_LIMIT_COUNT, A.TEACH_JOIN_UNIT, A.TEACH_BACKUP_COUNT, A.TEACH_OFFLINE_COUNT, A.START_JOIN_DATE, A.TYPING_TEACHER_NAME, A.TEACHER_IDX, A.START_JOIN_TIME, A.END_JOIN_DATE, A.END_JOIN_TIME, A.TEACH_DAY, A.START_DATE, A.START_TIME, A.ADD_DATE, A.END_DATE, A.END_TIME, A.CANCLE_USE_YN, A.START_CANCLE_DATE, A.START_CANCLE_TIME, A.END_CANCLE_DATE, A.END_CANCLE_TIME, A.CANCLE_GUID, A.APPLY_LIMIT, A.PLAN_FILE_NAME, A.REAL_FILE_NAME, A.FILE_EXTENSION, A.FILE_SIZE, A.MEMBER_YN, A.CERTIFICATE_YN, A.TEACHER_NAME,A.MEMBER_KEY, A.CATEGORY_NAME, A.TEACH_JOIN_COUNT, A.TEACH_BACKUP_JOIN_COUNT, A.TEACH_OFF_JOIN_COUNT, A.GROUP_NAME, A.PRINT_SEQ, A.IMAGE_PLAN_FILE_NAME, A.IMAGE_REAL_FILE_NAME, A.IMAGE_FILE_EXTENSION, A.IMAGE_FILE_SIZE, a.LIMIT_HAK_YN, a.family_count_yn, a.agent_yn, a.school_info_yn, a.school_grade_yn, a.remark_yn, getCodeIdToCodeName('CMS', 'C0020', a.limit_hak) AS LIMIT_HAK_STR, getCodeIdToCodeName('CMS', 'C0020', a.limit_hak2) AS LIMIT_HAK2_STR, a.neis_location_yn, a.neis_cd_yn, a.neis_training_num_yn, a.large_category_idx, a.organization_yn, a.rank_yn, a.course_taken_yn, (SELECT code_name FROM TEACH_CODE2 WHERE teach_code = a.large_category_idx) as large_category_name, program_classification1, program_classification2, program_classification3, program_subject, program_age_div, (SELECT code_name FROM TEACH_CODE2 WHERE teach_code = a.program_subject) as program_subject_name, (SELECT code_name FROM TEACH_CODE WHERE large_code = a.program_classification1 AND mid_code = '--' AND small_code = '--') as program_classification1_name, (SELECT code_name FROM TEACH_CODE WHERE large_code = a.program_classification1 AND mid_code = a.program_classification2 AND small_code = '--') as program_classification2_name, (SELECT code_name FROM TEACH_CODE WHERE large_code = a.program_classification1 AND mid_code = a.program_classification2 AND small_code = a.program_classification3) as program_classification3_name FROM ( SELECT (SELECT COUNT(*) FROM STUDENT WHERE HOMEPAGE_ID = a.HOMEPAGE_ID AND GROUP_IDX = a.GROUP_IDX AND CATEGORY_IDX = a.CATEGORY_IDX AND TEACH_IDX = a.TEACH_IDX AND MEMBER_KEY = #{member_key} AND apply_status != '99' AND DELETE_YN != 'Y') as STATUS, (SELECT APPLY_STATUS FROM STUDENT WHERE HOMEPAGE_ID = a.HOMEPAGE_ID AND GROUP_IDX = a.GROUP_IDX AND CATEGORY_IDX = a.CATEGORY_IDX AND TEACH_IDX = a.TEACH_IDX AND MEMBER_KEY = #{member_key} AND apply_status != '99' AND DELETE_YN != 'Y') as APPLY_STATUS, a.HOMEPAGE_ID, a.GROUP_IDX, a.CATEGORY_IDX, a.TEACH_IDX, a.TEACH_NAME, a.TEACH_DESC, a.TEACH_ETC, a.TEACH_STAGE, a.TEACH_TARGET, a.LIMIT_HAK, a.LIMIT_HAK2, a.TEACH_LIMIT_COUNT, a.TEACH_JOIN_UNIT, a.TEACH_BACKUP_COUNT, a.TEACH_OFFLINE_COUNT, a.START_JOIN_DATE, a.TYPING_TEACHER_NAME, a.TEACHER_IDX, a.START_JOIN_TIME, a.END_JOIN_DATE, a.END_JOIN_TIME, a.TEACH_DAY, a.START_DATE, a.START_TIME, a.ADD_DATE, a.PRINT_SEQ, a.END_DATE, a.END_TIME, a.cancle_use_yn, a.start_cancle_date, a.start_cancle_time, a.end_cancle_date, a.end_cancle_time, a.cancle_guid, a.APPLY_LIMIT, a.PLAN_FILE_NAME, a.REAL_FILE_NAME, a.FILE_EXTENSION, a.FILE_SIZE, a.MEMBER_YN, a.CERTIFICATE_YN, a.TEACH_JOIN_LIMIT_UNIT, a.TEACH_JOIN_LIMIT_VALUE, b.TEACHER_NAME,b.MEMBER_KEY, c.CATEGORY_NAME,d.GROUP_NAME, a.START_JOIN_DATE||' '||a.START_JOIN_TIME REQ_START_DATE, a.END_JOIN_DATE||' '||a.END_JOIN_TIME REQ_END_DATE, NVL((SELECT COUNT(*) FROM STUDENT WHERE DELETE_YN = 'N' AND HOMEPAGE_ID = a.HOMEPAGE_ID AND GROUP_IDX = a.GROUP_IDX AND CATEGORY_IDX = a.CATEGORY_IDX AND TEACH_IDX = a.TEACH_IDX AND APPLY_STATUS='1' AND APPLY_TYPE != 'CMS' GROUP BY TEACH_IDX), 0) AS TEACH_JOIN_COUNT, NVL((SELECT COUNT(*) FROM STUDENT WHERE DELETE_YN = 'N' AND HOMEPAGE_ID = a.HOMEPAGE_ID AND GROUP_IDX = a.GROUP_IDX AND CATEGORY_IDX = a.CATEGORY_IDX AND TEACH_IDX = a.TEACH_IDX AND APPLY_STATUS='2' GROUP BY TEACH_IDX), 0) AS TEACH_BACKUP_JOIN_COUNT, NVL((SELECT COUNT(*) FROM STUDENT WHERE DELETE_YN = 'N' AND HOMEPAGE_ID = a.HOMEPAGE_ID AND GROUP_IDX = a.GROUP_IDX AND CATEGORY_IDX = a.CATEGORY_IDX AND TEACH_IDX = a.TEACH_IDX AND APPLY_STATUS='1' AND APPLY_TYPE = 'CMS' GROUP BY TEACH_IDX), 0) AS TEACH_OFF_JOIN_COUNT, a.IMAGE_PLAN_FILE_NAME, a.IMAGE_REAL_FILE_NAME, a.IMAGE_FILE_EXTENSION, a.IMAGE_FILE_SIZE, a.LIMIT_HAK_YN, a.family_count_yn, a.agent_yn, a.school_info_yn, a.school_grade_yn, a.remark_yn, a.neis_location_yn, a.neis_cd_yn, a.neis_training_num_yn, a.large_category_idx, a.organization_yn, a.rank_yn, a.course_taken_yn, (SELECT code_name FROM TEACH_CODE2 WHERE teach_code = a.large_category_idx) as large_category_name, program_classification1, program_classification2, program_classification3, program_subject, program_age_div, a.black_yn FROM TEACH a, TEACHER b, TEACH_CATEGORY c, TEACH_CATEGORY_GROUP d WHERE a.HOMEPAGE_ID = b.HOMEPAGE_ID(+) AND a.TEACHER_IDX = b.TEACHER_IDX(+) AND a.HOMEPAGE_ID = c.HOMEPAGE_ID(+) AND a.GROUP_IDX = c.GROUP_IDX(+) AND a.CATEGORY_IDX = c.CATEGORY_IDX(+) AND a.HOMEPAGE_ID = d.HOMEPAGE_ID(+) AND a.GROUP_IDX = d.GROUP_IDX(+) AND a.HOMEPAGE_ID = #{homepage_id}
