ABS(SYSDATE - (TO_DATE(a.START_JOIN_DATE ||' '|| a.START_JOIN_TIME, 'YYYY-MM-DD HH24:MI'))) ASC, ABS(SYSDATE - (TO_DATE(a.END_JOIN_DATE ||' '|| a.END_JOIN_TIME, 'YYYY-MM-DD HH24:MI'))) ASC, a.PRINT_SEQ ASC
ABS(SYSDATE - (TO_DATE(a.START_JOIN_DATE ||' '|| a.START_JOIN_TIME, 'YYYY-MM-DD HH24:MI'))) ASC, ABS(SYSDATE - (TO_DATE(a.END_JOIN_DATE ||' '|| a.END_JOIN_TIME, 'YYYY-MM-DD HH24:MI'))) ASC, a.PRINT_SEQ ASC
) A
