_key} AND apply_status != '99' AND DELETE_YN != 'Y') as STATUS, (SELECT APPLY_STATUS FROM STUDENT WHERE HOMEPAGE_ID = a.HOMEPAGE_ID AND GROUP_IDX = a.GROUP_IDX AND CATEGORY_IDX = a.CATEGORY_IDX AND TEACH_IDX = a.TEACH_IDX AND MEMBER_KEY = #{member_key} AND apply_status != '99' AND DELETE_YN != 'Y') as APPLY_STATUS, a.black_yn, a.HOMEPAGE_ID, a.GROUP_IDX, a.CATEGORY_IDX, a.TEACH_IDX, a.TEACH_NAME, a.TEACH_DESC, a.TEACH_ETC, a.TEACH_STAGE, a.TEACH_TARGET, a.LIMIT_HAK, a.LIMIT_HAK2, a.TEACH_LIMIT_COUNT, a.TEACH_JOIN_UNIT, a.TEACH_BACKUP_COUNT, a.TEACH_OFFLINE_COUNT, a.START_JOIN_DATE, a.TYPING_TEACHER_NAME, a.TEACHER_IDX, a.START_JOIN_TIME, a.END_JOIN_DATE, a.END_JOIN_TIME, a.TEACH_DAY, a.START_DATE, a.START_TIME, a.END_DATE, a.END_TIME, a.PLAN_FILE_NAME, a.REAL_FILE_NAME, a.FILE_EXTENSION, a.FILE_SIZE, a.MEMBER_YN, a.CERTIFICATE_YN, a.TEACH_JOIN_LIMIT_UNIT, a.TEACH_JOIN_LIMIT_VALUE, b.TEACHER_NAME,b.MEMBER_KEY, c.CATEGORY_NAME,d.GROUP_NAME, a.START_JOIN_DATE||' '||a.START_JOIN_TIME REQ_START_DATE, a.END_JOIN_DATE||' '||a.END_JOIN_TIME REQ_END_DATE, NVL((SELECT COUNT(*) FROM STUDENT WHERE DELETE_YN = 'N' AND HOMEPAGE_ID = a.HOMEPAGE_ID AND GROUP_IDX = a.GROUP_IDX AND CATEGORY_IDX = a.CATEGORY_IDX AND TEACH_IDX = a.TEACH_IDX AND APPLY_STATUS='1' AND APPLY_TYPE != 'CMS' GROUP BY TEACH_IDX), 0) AS TEACH_JOIN_COUNT, NVL((SELECT COUNT(*) FROM STUDENT WHERE DELETE_YN = 'N' AND HOMEPAGE_ID = a.HOMEPAGE_ID AND GROUP_IDX = a.GROUP_IDX AND CATEGORY_IDX = a.CATEGORY_IDX AND TEACH_IDX = a.TEACH_IDX AND APPLY_STATUS='2' GROUP BY TEACH_IDX), 0) AS TEACH_BACKUP_JOIN_COUNT, NVL((SELECT COUNT(*) FROM STUDENT WHERE DELETE_YN = 'N' AND HOMEPAGE_ID = a.HOMEPAGE_ID AND GROUP_IDX = a.GROUP_IDX AND CATEGORY_IDX = a.CATEGORY_IDX AND TEACH_IDX = a.TEACH_IDX AND APPLY_STATUS='1' AND APPLY_TYPE = 'CMS' GROUP BY TEACH_IDX), 0) AS TEACH_OFF_JOIN_COUNT, a.IMAGE_PLAN_FILE_NAME, a.IMAGE_REAL_FILE_NAME, a.IMAGE_FILE_EXTENSION, a.IMAGE_FILE_SIZE, a.LIMIT_HAK_YN, a.family_count_yn, a.agent_yn, a.school_