SELECT COUNT(*) FROM ( SELECT CASE WHEN TO_DATE(A.end_date || ' ' || A.end_time, 'YYYY-MM-DD HH24:MI') < SYSDATE THEN '9' WHEN A.status = 0 AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.req_start_date AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.req_end_date AND A.teach_limit_count > A.teach_join_count THEN '0' WHEN A.status = 0 AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.req_start_date AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.req_end_date AND A.teach_limit_count <= A.teach_join_count AND A.teach_backup_count > A.teach_backup_join_count THEN '1' WHEN A.status = 0 AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.req_start_date AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.req_end_date AND A.teach_limit_count <= A.teach_join_count AND A.teach_backup_count <= A.teach_backup_join_count THEN '5' WHEN A.status = 0 AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.req_start_date THEN '6' WHEN A.status = 0 AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.req_end_date THEN '4' WHEN A.status = 1 AND A.apply_status = '1' AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.req_start_date AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.req_end_date THEN '2' WHEN A.status = 1 AND A.apply_status = '2' AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.req_start_date AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.req_end_date THEN '3' WHEN A.status = 1 AND A.apply_status = '99' AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.req_start_date AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.req_end_date THEN '7' WHEN A.status = 1 AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.req_end_date THEN '4' END as TEACH_STATUS, A.HOMEPAGE_ID, A.GROUP_IDX, A.CATEGORY_IDX, A.TEACH_IDX, A.TEACH_NAME, A.TEACH_DESC, A.TEACH_ETC, A.TEACH_STAGE, A.TEACH_TARGET, A.LIMIT_HAK, a.LIMIT_HAK2, A.TEACH_LIMIT_COUNT, A.TEACH_JOIN_UNIT, A.TEACH_BACKUP_COUNT, A.TEACH_OFFLINE_COUNT, A.START_JOIN_DATE, A.TYPING_TEACHER_NAME, A.TEACHER_IDX, A.START_JOIN_TIME, A.END_JOIN_DATE, A.END_JOIN_TIME, A.TEACH_DAY, A.START_DATE, A.START_TIME, A.END_DATE, A.END_TIME, A.PLAN_FILE_NAME, A.REAL_FILE_NAME, A.FILE_EXTENSION, A.FILE_SIZE, A.MEMBER_YN, A.CERTIFICATE_YN, A.TEACHER_NAME,A.MEMBER_KEY, A.CATEGORY_NAME, A.TEACH_JOIN_COUNT, A.TEACH_BACKUP_JOIN_COUNT, A.TEACH_OFF_JOIN_COUNT, A.GROUP_NAME, A.IMAGE_PLAN_FILE_NAME, A.IMAGE_REAL_FILE_NAME, A.IMAGE_FILE_EXTENSION, A.IMAGE_FILE_SIZE, (SELECT HOMEPAGE_ALIAS FROM CMS_HOMEPAGE WHERE HOMEPAGE_ID = A.HOMEPAGE_ID) AS HOMEPAGE_ALIAS, (SELECT CONTEXT_PATH FROM CMS_HOMEPAGE WHERE HOMEPAGE_ID = A.HOMEPAGE_ID) AS CONTEXT_PATH, req_start_date, req_end_date, APPLY_STATUS, a.LIMIT_HAK_YN, a.family_count_yn, a.agent_yn, a.school_info_yn, a.school_grade_yn, a.remark_yn, getCodeIdToCodeName('CMS', 'C0020', a.limit_hak) AS LIMIT_HAK_STR, getCodeIdToCodeName('CMS', 'C0020', a.limit_hak2) AS LIMIT_HAK2_STR FROM ( SELECT (SELECT COUNT(*) FROM STUDENT WHERE HOMEPAGE_ID = a.HOMEPAGE_ID AND GROUP_IDX = a.GROUP_IDX AND CATEGORY_IDX = a.CATEGORY_IDX AND TEACH_IDX = a.TEACH_IDX AND MEMBER_KEY = #{member_key} AND apply_status != '99' AND DELETE_YN != 'Y') as STATUS, (SELECT APPLY_STATUS FROM STUDENT WHERE HOMEPAGE_ID = a.HOMEPAGE_ID AND GROUP_IDX = a.GROUP_IDX AND CATEGORY_IDX = a.CATEGORY_IDX AND TEACH_IDX = a.TEACH_IDX AND MEMBER_KEY = #{member_key} AND apply_status != '99' AND DELETE_YN != 'Y') as APPLY_STATUS, a.HOMEPAGE_ID, a.GROUP_IDX, a.CATEGORY_IDX, a.TEACH_IDX, a.TEACH_NAME, a.TEACH_DESC, a.TEACH_ETC, a.TEACH_STAGE, a.TEACH_TARGET, a.LIMIT_HAK, a.LIMIT_HAK2, a.TEACH_LIMIT_COUNT, a.TEACH_JOIN_UNIT, a.TEACH_BACKUP_COUNT, a.TEACH_OFFLINE_COUNT, a.START_JOIN_DATE, a.TYPING_TEACHER_NAME, a.TEACHER_IDX, a.START_JOIN_TIME, a.END_JOIN_DATE, a.END_JOIN_TIME, a.TEACH_DAY, a.START_DATE, a.START_TIME, a.END_DATE, a.END_TIME, a.PLAN_FILE_NAME, a.REAL_FILE_NAME, a.FILE_EXTENSION, a.FILE_SIZE, a.MEMBER_YN, a.CERTIFICATE_YN, a.TEACH_JOIN_LIMIT_UNIT, a.TEACH_JOIN_LIMIT_VALUE, b.TEACHER_NAME,b.MEMBER_KEY, c.CATEGORY_NAME,d.GROUP_NAME, a.START_JOIN_DATE||' '||a.START_JOIN_TIME REQ_START_DATE, a.END_JOIN_DATE||' '||a.END_JOIN_TIME REQ_END_DATE, NVL((SELECT COUNT(*) FROM STUDENT WHERE DELETE_YN = 'N' AND HOMEPAGE_ID = a.HOMEPAGE_ID AND GROUP_IDX = a.GROUP_IDX AND CATEGORY_IDX = a.CATEGORY_IDX AND TEACH_IDX = a.TEACH_IDX AND APPLY_STATUS='1' AND APPLY_TYPE != 'CMS' GROUP BY TEACH_IDX), 0) AS TEACH_JOIN_COUNT, NVL((SELECT COUNT(*) FROM STUDENT WHERE DELETE_YN = 'N' AND HOMEPAGE_ID = a.HOMEPAGE_ID AND GROUP_IDX = a.GROUP_IDX AND CATEGORY_IDX = a.CATEGORY_IDX AND TEACH_IDX = a.TEACH_IDX AND APPLY_STATUS='2' GROUP BY TEACH_IDX), 0) AS TEACH_BACKUP_JOIN_COUNT, NVL((SELECT COUNT(*) FROM STUDENT WHERE DELETE_YN = 'N' AND HOMEPAGE_ID = a.HOMEPAGE_ID AND GROUP_IDX = a.GROUP_IDX AND CATEGORY_IDX = a.CATEGORY_IDX AND TEACH_IDX = a.TEACH_IDX AND APPLY_STATUS='1' AND APPLY_TYPE = 'CMS' GROUP BY TEACH_IDX), 0) AS TEACH_OFF_JOIN_COUNT, a.IMAGE_PLAN_FILE_NAME, a.IMAGE_REAL_FILE_NAME, a.IMAGE_FILE_EXTENSION, a.IMAGE_FILE_SIZE, a.LIMIT_HAK_YN, a.family_count_yn, a.agent_yn, a.school_info_yn, a.school_grade_yn, a.remark_yn, a.neis_location_yn, a.neis_cd_yn, a.neis_training_num_yn, a.organization_yn, a.rank_yn, a.course_taken_yn FROM (SELECT * FROM TEACH WHERE 1 = 1
AND TEACH_NAME LIKE '%'||#{search_text}||'%'
AND TEACH_NAME LIKE '%'||#{searchKeyword1}||'%'
${logicFunction1} TEACH_NAME LIKE '%'||#{searchKeyword2}||'%'
${logicFunction2} TEACH_NAME LIKE '%'||#{searchKeyword3}||'%'
${logicFunction3} TEACH_NAME LIKE '%'||#{searchKeyword4}||'%'
AND START_DATE >= #{start_date}
AND START_DATE <= #{end_date}
AND START_JOIN_DATE >= #{start_join_date}
AND START_JOIN_DATE <= #{end_join_date}
AND homepage_id = #{homepage_id}
AND large_category_idx = #{large_category_idx}
AND group_idx = #{group_idx}
AND category_idx = #{category_idx}
AND USE_YN = 'Y' AND DELETE_YN = 'N' ) a, TEACHER b, TEACH_CATEGORY c, TEACH_CATEGORY_GROUP d WHERE a.HOMEPAGE_ID = b.HOMEPAGE_ID(+) AND a.TEACHER_IDX = b.TEACHER_IDX(+) AND a.HOMEPAGE_ID = c.HOMEPAGE_ID(+) AND a.GROUP_IDX = c.GROUP_IDX(+) AND a.CATEGORY_IDX = c.CATEGORY_IDX(+) AND a.HOMEPAGE_ID = d.HOMEPAGE_ID(+) AND a.GROUP_IDX = d.GROUP_IDX(+) --AND SYSDATE < TO_DATE(a.END_JOIN_DATE||' '||a.END_JOIN_TIME, 'YYYY-MM-DD HH24:MI') ORDER BY ABS(SYSDATE - (TO_DATE(a.START_JOIN_DATE ||' '|| a.START_JOIN_TIME, 'YYYY-MM-DD HH24:MI'))) ASC, ABS(SYSDATE - (TO_DATE(a.END_JOIN_DATE ||' '|| a.END_JOIN_TIME, 'YYYY-MM-DD HH24:MI'))) ASC, a.PRINT_SEQ ASC ) A )
WHERE
TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= req_end_date
TEACH_STATUS = #{status}

