SELECT A.*, (SELECT HOMEPAGE_ALIAS FROM CMS_HOMEPAGE WHERE HOMEPAGE_ID = A.HOMEPAGE_ID) AS HOMEPAGE_ALIAS FROM ( SELECT HOMEPAGE_ID, GROUP_IDX, CATEGORY_IDX, TEACH_IDX, TEACH_NAME, START_JOIN_DATE,START_JOIN_TIME,END_JOIN_DATE, END_JOIN_TIME, START_DATE, END_DATE, START_TIME, END_TIME, TEACH_DAY, TEACH_TARGET, TEACH_DESC, IMAGE_REAL_FILE_NAME, TEACH_STAGE, TEACH_LIMIT_COUNT, TEACH_JOIN_UNIT, TEACH_BACKUP_COUNT, TEACH_OFFLINE_COUNT, NVL((SELECT COUNT(*) FROM STUDENT WHERE DELETE_YN = 'N' AND HOMEPAGE_ID = a.HOMEPAGE_ID AND GROUP_IDX = a.GROUP_IDX AND CATEGORY_IDX = a.CATEGORY_IDX AND TEACH_IDX = a.TEACH_IDX AND APPLY_STATUS='1' AND APPLY_TYPE != 'CMS' GROUP BY TEACH_IDX), 0) AS TEACH_JOIN_COUNT, NVL((SELECT COUNT(*) FROM STUDENT WHERE DELETE_YN = 'N' AND HOMEPAGE_ID = a.HOMEPAGE_ID AND GROUP_IDX = a.GROUP_IDX AND CATEGORY_IDX = a.CATEGORY_IDX AND TEACH_IDX = a.TEACH_IDX AND APPLY_STATUS='2' GROUP BY TEACH_IDX), 0) AS TEACH_BACKUP_JOIN_COUNT, NVL((SELECT COUNT(*) FROM STUDENT WHERE DELETE_YN = 'N' AND HOMEPAGE_ID = a.HOMEPAGE_ID AND GROUP_IDX = a.GROUP_IDX AND CATEGORY_IDX = a.CATEGORY_IDX AND TEACH_IDX = a.TEACH_IDX AND APPLY_STATUS='1' AND APPLY_TYPE = 'CMS' GROUP BY TEACH_IDX), 0) AS TEACH_OFF_JOIN_COUNT FROM TEACH a WHERE 1 = 1 AND HOMEPAGE_ID = #{homepage_id} AND DELETE_YN = 'N' AND USE_YN = 'Y' AND (TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDD'), 'YYYY-MM-DD') < TO_DATE(a.use_end_date, 'YYYY-MM-DD'))
AND LARGE_CATEGORY_IDX IN (${searchCate1})
ORDER BY ABS(SYSDATE - (TO_DATE(START_JOIN_DATE ||' '|| START_JOIN_TIME, 'YYYY-MM-DD HH24:MI'))) ASC, ABS(SYSDATE - (TO_DATE(END_JOIN_DATE ||' '|| END_JOIN_TIME, 'YYYY-MM-DD HH24:MI'))) ASC, PRINT_SEQ ASC ) A WHERE ROWNUM <= #{main_view_count}

